{
  "namespace": "cursos",
  "records": [
    {
      "id": "curso-001",
      "data": {
        "text": "Introducción al fundraising para startups en Latinoamérica. Este curso cubre cómo preparar un pitch deck, identificar inversionistas ángeles y fondos de venture capital en la región, y cómo estructurar una ronda pre-seed o seed."
      },
      "metadata": {
        "type": "course",
        "category": "fundraising",
        "author": "María González"
      }
    },
    {
      "id": "curso-002",
      "data": {
        "text": "Growth hacking para SaaS B2B. Estrategias de adquisición de usuarios, optimización de funnels de conversión, métricas clave como MRR, churn rate y LTV. Incluye casos de estudio de startups latinoamericanas que escalaron de 0 a 1M ARR."
      },
      "metadata": {
        "type": "course",
        "category": "growth",
        "author": "Carlos Mendoza"
      }
    },
    {
      "id": "curso-003",
      "data": {
        "text": "Legal y compliance para founders. Cómo constituir una empresa en Delaware vs. tu país local, acuerdos de accionistas, SAFE notes, term sheets, y regulaciones fiscales para startups con operaciones cross-border en Latam."
      },
      "metadata": {
        "type": "course",
        "category": "legal",
        "author": "Ana Rodríguez"
      }
    }
  ]
}

{
  "namespace": "articulos",
