      "data": {
        "title": "Cómo validar tu idea de startup",
        "description": "Guía práctica de validación en 2 semanas",
        "content": "Usa entrevistas de problema, landing pages con Carrd, y ads de bajo presupuesto en Meta para medir intención de compra real antes de escribir una línea de código."
      },
      "metadata": {
        "type": "article",
        "topic": "validacion"
      }
    },
    {
      "id": "art-002",
      "data": {
        "title": "Product-market fit",
        "description": "Señales claras de que lo encontraste",
        "content": "Retención orgánica mayor al 40% en semana 4, usuarios que recomiendan sin incentivos, y willingness to pay demostrado. El framework de Sean Ellis aplicado al contexto latinoamericano."
      },
      "metadata": {
        "type": "article",
        "topic": "product-market-fit"
      }
    }
  ]
}

